SELECT t.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cd_dm.code_label AS dliv_method_cd_nm, cd_dpt.code_label AS dliv_pay_type_cd_nm FROM pd_dliv_tmplt t LEFT JOIN sy_site ste ON ste.site_id = t.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = t.vendor_id LEFT JOIN sy_code cd_dm ON cd_dm.code_grp = 'DLIV_METHOD' AND cd_dm.code_value = t.dliv_method_cd LEFT JOIN sy_code cd_dpt ON cd_dpt.code_grp = 'DLIV_PAY_TYPE' AND cd_dpt.code_value = t.dliv_pay_type_cd
ORDER BY t.dliv_tmplt_id ASC ORDER BY t.dliv_tmplt_id DESC ORDER BY t.dliv_tmplt_nm ASC ORDER BY t.dliv_tmplt_nm DESC ORDER BY t.reg_date ASC ORDER BY t.reg_date DESC ORDER BY t.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT t.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cd_dm.code_label AS dliv_method_cd_nm, cd_dpt.code_label AS dliv_pay_type_cd_nm FROM pd_dliv_tmplt t LEFT JOIN sy_site ste ON ste.site_id = t.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = t.vendor_id LEFT JOIN sy_code cd_dm ON cd_dm.code_grp = 'DLIV_METHOD' AND cd_dm.code_value = t.dliv_method_cd LEFT JOIN sy_code cd_dpt ON cd_dpt.code_grp = 'DLIV_PAY_TYPE' AND cd_dpt.code_value = t.dliv_pay_type_cd
ORDER BY t.dliv_tmplt_id ASC ORDER BY t.dliv_tmplt_id DESC ORDER BY t.dliv_tmplt_nm ASC ORDER BY t.dliv_tmplt_nm DESC ORDER BY t.reg_date ASC ORDER BY t.reg_date DESC ORDER BY t.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

